VALUES
  ('heelevel3-6f0ba476-moex-00572', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-110-9b7ab1bb', 'sub-heelevel3-6f0ba476-02', NULL, 'single_choice', '甲登記為A地所有人，於A地上設定20年期限之普通地上權於乙。甲與乙約定，乙每年應支付 甲地租新臺幣15萬元，共計20年地租之約定。某日夜晚，甲於A地上掩埋大量劇毒廢棄物，致 A地受有縱經百年休養亦無法回復，完全不能達原來使用之損害。下列敘述，何者正確？', '["乙得支付未到期之3年分地租後，拋棄其地上權", "乙得支付未到期之1年分地租，拋棄其地上權", "乙得支付未到期2年分之地租，拋棄其地上權", "乙得拋棄其地上權，並免地租支付義務"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:32+00:00", "source_pdf_sha1": "41c49d8354fb", "answer_pdf_sha1": "ef3e66e2c719", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "323", "s": "0704", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
