  ('heelevel3-6f0ba476-moex-00574', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-110-9b7ab1bb', 'sub-heelevel3-6f0ba476-02', NULL, 'single_choice', '張大雄與李靜香結婚，並約定妻冠夫姓而成張李靜香，二人生子名為小明，並約定該子從母姓， 小明之姓名應為下列何者？', '["李小明", "張李小明", "李張小明", "張小明"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:32+00:00", "source_pdf_sha1": "41c49d8354fb", "answer_pdf_sha1": "ef3e66e2c719", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "323", "s": "0704", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00575', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-110-9b7ab1bb', 'sub-heelevel3-6f0ba476-02', NULL, 'single_choice', '甲為A照護中心之代表人，乙受監護之宣告，甲於何種情形，不得為乙之監護人？', '["甲為乙之配偶", "甲為乙之四親等之堂兄", "甲為乙之三親等之姨丈", "甲為乙之女婿"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:32+00:00", "source_pdf_sha1": "41c49d8354fb", "answer_pdf_sha1": "ef3e66e2c719", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "323", "s": "0704", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00576', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-110-9b7ab1bb', 'sub-heelevel3-6f0ba476-02', NULL, 'single_choice', '下列關於法定繼承人之敘述，何者錯誤？', '["民法第1138條第2款所稱之母，自不包含父所娶之後妻在內", "民法第1138條第3款所稱兄弟姊妹，包括同父異母或同母異父之兄弟姊妹", "養子女對本生父母之遺產，無繼承權", "法定繼承人如喪失我國國籍者，不得繼承被繼承人之遺產"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:32+00:00", "source_pdf_sha1": "41c49d8354fb", "answer_pdf_sha1": "ef3e66e2c719", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "323", "s": "0704", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00577', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-110-9b7ab1bb', 'sub-heelevel3-6f0ba476-02', NULL, 'single_choice', '下列關於繼承權有無之敘述，何者錯誤？', '["繼承開始後，繼承人已取得繼承權", "繼承開始後已取得繼承權，仍可能因變造遺囑而喪失", "繼承開始前喪失繼承權，仍可能因被繼承人宥恕而回復", "對被繼承人重大虐待者，應經被繼承人遺囑表示，始喪失繼承權"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:32+00:00", "source_pdf_sha1": "41c49d8354fb", "answer_pdf_sha1": "ef3e66e2c719", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "323", "s": "0704", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00578', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-110-9b7ab1bb', 'sub-heelevel3-6f0ba476-02', NULL, 'single_choice', '甲因其子乙結婚而贈與乙新臺幣（下同）100 萬元。甲與丙再婚，翌日甲即死亡。甲死亡時有財 產500萬元，對丁負債200萬元。甲之繼承人乙及丙發現甲之遺囑中表示，遺贈甲之母戊250萬 元。下列敘述，何者正確？', '["丙受有特留分100萬元保障", "乙得對戊主張扣減遺贈50萬元", "乙的特留分較丙多50萬元", "戊得向乙丙主張酌給遺產權"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:32+00:00", "source_pdf_sha1": "41c49d8354fb", "answer_pdf_sha1": "ef3e66e2c719", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "323", "s": "0704", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00579', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-110-3e700a6a', 'sub-heelevel3-6f0ba476-05', NULL, 'essay', '何謂「林達爾租稅」（Lindahltax）？該制度是以何種課稅原則課稅。
（15 分）
有 a、b 兩人，a 與 b 對公共財的邊際願付價格函數分別為 Pa=24−2G
與 Pb=12−G，此處 Pi為 i對公共財之邊際願付價格，G則代表公共財
之數量。提供公共財之邊際成本為 MC，MC為公共財數量 G的函數，
且 MC 與 G 的關係為 MC=1×G。請問 a、b 兩人的林達爾租稅各是多
少？（10分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:32+00:00", "source_pdf_sha1": "87eeb6c1355b", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "323", "s": "1001", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "租稅各論", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00580', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-110-3e700a6a', 'sub-heelevel3-6f0ba476-05', NULL, 'essay', '假設只有 x、y 兩種財貨，兩財貨之受補償需求曲線均為負斜率。一開
始，政府只對 y 財課徵貨物稅，x 財為免稅。倘若現在政府也要對 x 財
課徵貨物稅，而y財的稅率維持不變。試分析對x 財課稅對整體貨物稅
超額負擔之影響。（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:32+00:00", "source_pdf_sha1": "87eeb6c1355b", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "323", "s": "1001", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "租稅各論", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
